class Solution:
    def captureForts(self, forts):
        n = len(forts)
        best = 0
        for i in range(n):
            if forts[i] == 0:
                continue
            for j in range(i + 1, n):
                if forts[j] == 0:
                    continue
                if forts[i] != forts[j] and all(forts[k] == 0 for k in range(i + 1, j)):
                    best = max(best, j - i - 1)
        return best

solutions.python:
class Solution:
    def captureForts(self, forts):
        ans = 0
        last = -1
        for i, v in enumerate(forts):
            if v != 0:
                if last != -1 and forts[last] != v:
                    ans = max(ans, i - last - 1)
                last = i
        return ans

