var captureForts = function(forts) {
    let ans = 0;
    let last = -1;
    for (let i = 0; i < forts.length; i++) {
        if (forts[i] !== 0) {
            if (last !== -1 && forts[last] !== forts[i]) {
                ans = Math.max(ans, i - last - 1);
            }
            last = i;
        }
    }
    return ans;
